12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	};
19	
20	const BLOCK_PRICE_FOR_3_ALIKE = 60;
21	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
22	const ENCHANTMENT_SURCHARGE_MULTIPLIER = 0.3;
23	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
24	const LOYALTY_DISCOUNT_MIN_YEARS = 2;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	
27	export function generateQuote(items: Item[], customer: Customer): { basePremium: number } {
28	  const nonCursedCountsByType: Record<string, number> = {};
29	  let cursedPremium = 0;
30	  let enchantmentSurcharge = 0;
31	
32	  for (const item of items) {
33	    const itemBasePremium = BASE_PREMIUMS[item.type];
34	    if (item.cursed) {
35	      cursedPremium += itemBasePremium * CURSED_SURCHARGE_MULTIPLIER;
36	    } else {
37	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
38	      if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
39	        enchantmentSurcharge += itemBasePremium * ENCHANTMENT_SURCHARGE_MULTIPLIER;
40	      }
41	    }
42	  }
43	
44	  let basePremium = cursedPremium;
45	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
46	    if (count === 3) {
47	      basePremium += BLOCK_PRICE_FOR_3_ALIKE;
48	    } else {
49	      basePremium += count * BASE_PREMIUMS[type];
50	    }
51	  }
52	  basePremium += enchantmentSurcharge;
53	
54	  if (customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_MIN_YEARS) {
55	    basePremium = basePremium * LOYALTY_DISCOUNT_MULTIPLIER;
56	  }
57	
58	  return { basePremium };
59	}
